import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Tariff per kWh',
        data: [12, 12, 15, 22, 22, 18, 15, 24, 24, 15, 12],
      },
    ],
    options: {
      chart: {
        type: 'line',
        height: 350,
      },
      stroke: {
        curve: 'linestep',
      },
      dataLabels: {
        enabled: false,
      },
      title: {
        text: 'Electricity Tariff by Time of Day',
        align: 'left',
      },
      subtitle: {
        text: "curve: 'linestep' steps to each new value at the point itself",
        align: 'left',
      },
      xaxis: {
        categories: [
          '00:00',
          '02:00',
          '04:00',
          '06:00',
          '08:00',
          '10:00',
          '12:00',
          '14:00',
          '16:00',
          '18:00',
          '20:00',
        ],
      },
      yaxis: {
        labels: {
          formatter: function (val) {
            return val + '¢'
          },
        },
      },
      markers: {
        hover: {
          sizeOffset: 4,
        },
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
